SELECT download.*
FROM upload join event using (id_upload) join download using (id_event)
WHERE quality = 'FullHD';

SELECT *
FROM EVENT
WHERE date = '2023-02-05';

begin;
insert into film (name, genre, country, release_date)
values ('Bratrstvo sigma', 'Drama', 'Slovensko', to_date('2023-04-15', 'YYYY-MM-DD'));
insert into service_user (registration_date, nickname)
values (to_date('2023-02-15', 'YYYY-MM-DD'), 'Frajer222');
SELECT film.name, film.release_date, upload.id_upload, upload.quality, service_user.nickname
from film
         left join upload on film.id_film = upload.id_film
         full outer join service_user on upload.id_user = service_user.id_user;
rollback;

CREATE OR REPLACE VIEW vyprselo as
(
SELECT *
from subscription
where end_date between '2022-01-01' and '2025-06-01'

    );

begin;
update vyprselo
set end_date=to_date('2025-05-08', 'YYYY-MM-DD');
select *
from vyprselo;
rollback;

begin;
insert into moderator (id_user, start_date)
select id_user, start_date
from (select id_user, to_date('2026-05-25', 'YYYY-MM-DD') as start_date
      from service_user
      order by registration_date desc) vstup
limit 1;
select *
from moderator;
rollback;

--původní
select service_user.nickname, subscription.end_date
from service_user
         join subscription using (id_user);
--dotaz
begin;
update subscription
set end_date=to_date('2024-12-01', 'YYYY-MM-DD')
where id_user in (select service_user.id_user
                  from service_user
                           join subscription using (id_user)
                  where end_date = to_date('2024-11-30', 'YYYY-MM-DD'));
select service_user.nickname, subscription.end_date
from service_user
         join subscription using (id_user);
rollback;

begin;

insert into film (name, genre, country, release_date)
values ('Avengers 18', 'Drama', 'Slovensko', to_date('2027-04-15', 'YYYY-MM-DD'));
select *
from film;
delete
from film
where id_film in (select id_film
                  from film
                  except
                  select id_film
                  from film
                           join upload using (id_film));
select *
from film;
rollback;

select service_user.*, (select count(*) from upload where upload.id_user = service_user.id_user) as pocet_uploadu
from service_user
order by pocet_uploadu desc, registration_date asc;
